mapper.sql:
p.deleted_at IS NULL

    AND p.category = #{request.category}


    AND (
        LOWER(p.title) LIKE CONCAT('%', LOWER(#{request.keyword}), '%')
        OR LOWER(p.content) LIKE CONCAT('%', LOWER(#{request.keyword}), '%')
    )

mapper.select:
SELECT

FROM community_posts p

WHERE


LIMIT #{limit}
OFFSET #{offset}
